 78→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 79→        super.onViewCreated(view, savedInstanceState)
 80→
 81→        val nonNullActivity = requireActivity()
 82→        with(StatsFragmentBinding.bind(view)) {
 83→            binding = this
 84→            with(nonNullActivity as AppCompatActivity) {
 85→                setSupportActionBar(toolbar)
 86→                supportActionBar?.let {
 87→                    it.setHomeButtonEnabled(true)
 88→                    it.setDisplayHomeAsUpEnabled(true)
 89→                }
 90→            }
 91→            initializeViewModels(nonNullActivity, savedInstanceState == null, savedInstanceState)
 92→            initializeViews()
 93→        }
