110→        statsPager.offscreenPageLimit = 2
111→        selectedTabListener = SelectedTabListener(viewModel)
112→        TabLayoutMediator(tabLayout, statsPager) { tab, position ->
113→            tab.text = adapter.getTabTitle(position)
