227→    @Suppress("MagicNumber")
228→    private fun StatsFragmentBinding.handleSelectedSectionWithTrafficTab(
229→        selectedSection: StatsSection
230→    ) {
231→        val position = when (selectedSection) {
232→            TRAFFIC -> 0
233→            INSIGHTS -> 1
234→            SUBSCRIBERS -> 2
235→            DETAIL,
236→            INSIGHT_DETAIL,
237→            TOTAL_LIKES_DETAIL,
238→            TOTAL_COMMENTS_DETAIL,
239→            TOTAL_FOLLOWERS_DETAIL,
240→            ANNUAL_STATS -> null
241→            else -> null
242→        }
243→        position?.let {
244→            if (statsPager.currentItem != position) {
245→                tabLayout.removeOnTabSelectedListener(selectedTabListener)
246→                statsPager.setCurrentItem(position, false)
247→                tabLayout.addOnTabSelectedListener(selectedTabListener)
248→            }
249→        }
250→    }
