10→class DeepLinkUriUtils
11→@Inject constructor(private val siteStore: SiteStore, private val uriUtilsWrapper: UriUtilsWrapper) {
12→    private fun extractHostFromSite(site: SiteModel?): String? {
13→        return site?.url?.let { uriUtilsWrapper.parse(it).host }
14→    }
15→
16→    fun getRedirectUri(uri: UriWrapper): UriWrapper? {
17→        return uri.getQueryParameter(REDIRECT_TO_PARAM)?.let { uriUtilsWrapper.parse(it) }
18→    }
19→
20→    private fun extractSiteModelFromTargetHost(host: String): List<SiteModel> {
21→        return siteStore.getSitesByNameOrUrlMatching(host)
22→    }
23→
24→    fun hostToSite(siteUrl: String): SiteModel? {
25→        return extractSiteModelFromTargetHost(siteUrl).find { site ->
26→            // Check if a site is available with given targetHost
27→            val host = extractHostFromSite(site)
28→            host != null && host == siteUrl
29→        }
30→    }
31→
32→    fun blogIdToSite(blogId: String): SiteModel? {
33→        return blogId.toLongOrNull()?.let { siteStore.getSiteBySiteId(it) }
34→    }
35→
36→    /**
37→     * Tracking URIs like `public-api.wordpress.com/mbar/...` come from emails and should be handled here
38→     */
39→    fun isTrackingUrl(uri: UriWrapper): Boolean {
40→        // https://public-api.wordpress.com/mbar/
41→        return uri.host == HOST_API_WORDPRESS_COM &&
42→                uri.pathSegments.firstOrNull() == MOBILE_TRACKING_PATH
43→    }
44→
45→    fun isWpLoginUrl(uri: UriWrapper): Boolean {
46→        // https://wordpress.com/wp-login.php/
47→        return uri.host == HOST_WORDPRESS_COM &&
48→                uri.pathSegments.firstOrNull() == WP_LOGIN
49→    }
50→
51→    companion object {
52→        private const val HOST_API_WORDPRESS_COM = "public-api.wordpress.com"
53→        private const val MOBILE_TRACKING_PATH = "mbar"
54→        private const val WP_LOGIN = "wp-login.php"
55→        private const val REDIRECT_TO_PARAM = "redirect_to"
56→    }
57→}
