 20→class EditorLinkHandler
 21→@Inject constructor(
 22→    private val deepLinkUriUtils: DeepLinkUriUtils,
 23→    private val postStore: PostStore
 24→) : DeepLinkHandler {
 25→    private val _toast = MutableLiveData<Event<Int>>()
 26→
 27→    override fun toast(): LiveData<Event<Int>> {
 28→        return _toast
 29→    }
 30→
 31→    /**
 32→     * Builds navigate action from URL like:
 33→     * https://wordpress.com/post/siteNameOrUrl/postId
 34→     * where siteNameOrUrl and postID are optional
 35→     * or App links like wordpress://post?blogId=798&postId=1231
 36→     */
 37→    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 38→        var hasSiteParam = false
 39→        var hasPostParam = false
 40→        val (targetSite, targetPost) = if (uri.host == POST_PATH) {
 41→            // Handles wordpress://post?blogId=798&postId=1231
 42→            val targetSite = uri.getQueryParameter(BLOG_ID).also { hasSiteParam = it != null }?.blogIdToSite()
 43→            val targetPost = uri.getQueryParameter(POST_ID).also { hasPostParam = it != null }?.toPost(targetSite)
 44→            targetSite to targetPost
 45→        } else {
 46→            // Handles https://wordpress.com/post/siteNameOrUrl/postId
 47→            val pathSegments = uri.pathSegments
 48→            val targetSite = pathSegments.getOrNull(1).also { hasSiteParam = it != null }?.hostNameToSite()
 49→            val targetPost = pathSegments.getOrNull(2).also { hasPostParam = it != null }?.toPost(targetSite)
 50→            targetSite to targetPost
 51→        }
 52→        return openEditorForSiteAndPost(hasSiteParam, hasPostParam, targetSite, targetPost)
 53→    }
 54→
 55→    /**
 56→     * Returns true if the URI should be handled by EditorLinkHandler.
 57→     * The handled links are `wordpress.com/post...1
 58→     */
 59→    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 60→        return (uri.host == DeepLinkingIntentReceiverViewModel.HOST_WORDPRESS_COM &&
 61→                uri.pathSegments.firstOrNull() == POST_PATH) || uri.host == POST_PATH
 62→    }
 63→
 64→    override fun stripUrl(uri: UriWrapper): String {
 65→        return if (uri.host == POST_PATH) {
 66→            // Transforms wordpress://post?blogId=798&postId=1231 to wordpress://post?blogId=blogId&postId=postId
 67→            buildString {
 68→                append("$APPLINK_SCHEME$POST_PATH")
 69→                val hasBlogIdParameter = uri.getQueryParameter(BLOG_ID) != null
 70→                val hasPostIdParameter = uri.getQueryParameter(POST_ID) != null
 71→                if (hasBlogIdParameter || hasPostIdParameter) {
 72→                    append("?")
 73→                    if (hasBlogIdParameter) {
 74→                        append("$BLOG_ID=$BLOG_ID")
 75→                        if (hasPostIdParameter) {
 76→                            append("&")
 77→                        }
 78→                    }
 79→                    if (hasPostIdParameter) {
 80→                        append("$POST_ID=$POST_ID")
 81→                    }
 82→                }
 83→            }
 84→        } else {
 85→            // Transforms https://wordpress.com/post/example.com/1231 to https://wordpress.com/post/siteNameOrUrl/postId
 86→            buildString {
 87→                append("${DeepLinkingIntentReceiverViewModel.HOST_WORDPRESS_COM}/$POST_PATH/")
 88→                if (uri.pathSegments.size > 2) {
 89→                    append("${DeepLinkingIntentReceiverViewModel.SITE_DOMAIN}/$POST_ID")
 90→                } else if (uri.pathSegments.size > 1) {
 91→                    append(DeepLinkingIntentReceiverViewModel.SITE_DOMAIN)
 92→                }
 93→            }
 94→        }
 95→    }
 96→
 97→    /**
 98→     * Converts BlogID if long or Site URL for other cases to a SiteModel
 99→     */
100→    private fun String.blogIdToSite(): SiteModel? {
101→        return deepLinkUriUtils.blogIdToSite(this) ?: this.hostNameToSite()
102→    }
103→
104→    /**
105→     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
106→     * to the host.
107→     */
108→    private fun String.hostNameToSite(): SiteModel? {
109→        return deepLinkUriUtils.hostToSite(this)
110→    }
111→
112→    /**
113→     * Converts the post ID in String to the local PostModel (if available).
114→     */
115→    private fun String.toPost(site: SiteModel?): PostModel? {
116→        val remotePostId: Long? = toLongOrNull()
117→        return if (site != null && remotePostId != null) {
118→            val post = postStore.getPostByRemotePostId(remotePostId, site)
119→            if (post == null) {
120→                _toast.value = Event(R.string.post_not_found)
121→            }
122→            post
123→        } else {
124→            null
125→        }
126→    }
127→
128→    private fun openEditorForSiteAndPost(
129→        hasSiteParam: Boolean,
130→        hasPostParam: Boolean,
131→        site: SiteModel?,
132→        post: PostModel?
133→    ): NavigateAction {
134→        return when {
135→            site == null -> {
136→                if (hasSiteParam) {
137→                    // Site not found, or host of site doesn't match the host in url
138→                    _toast.value = Event(R.string.blog_not_found)
139→                }
140→                // Open a new post editor with current selected site
141→                OpenEditor
142→            }
143→            post == null -> {
144→                if (hasPostParam) {
145→                    // Post not found. Open new post editor for given site.
146→                    _toast.value = Event(R.string.post_not_found)
147→                }
148→                // Open new post editor for given site
149→                OpenEditorForSite(site)
150→            }
151→            else -> OpenEditorForPost(site, post.id)
152→        }
153→    }
154→
155→    companion object {
156→        private const val POST_PATH = "post"
157→        private const val BLOG_ID = "blogId"
158→        private const val POST_ID = "postId"
159→    }
160→}
