 19→class StatsLinkHandler
 20→@Inject constructor(
 21→    private val deepLinkUriUtils: DeepLinkUriUtils,
 22→    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper
 23→) : DeepLinkHandler {
 24→    /**
 25→     * Builds navigate action from URL like:
 26→     * https://wordpress.com/stats/$timeframe/$site
 27→     * where timeframe and site are optional
 28→     * or
 29→     * wordpress://stats
 30→     */
 31→    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 32→        if (jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage()) return OpenJetpackStaticPosterView
 33→
 34→        val pathSegments = uri.pathSegments
 35→        val offset = if (uri.host == STATS_PATH) 0 else 1
 36→
 37→        val firstCandidate = pathSegments.getOrNull(offset)
 38→        val secondCandidate = pathSegments.getOrNull(offset + 1)
 39→
 40→        val statsTimeframe = firstCandidate?.toStatsTimeframe()
 41→        val site = if (statsTimeframe != null) {
 42→            secondCandidate?.toSite()
 43→        } else {
 44→            firstCandidate?.toSite()
 45→        }
 46→
 47→        return when {
 48→            site != null && statsTimeframe != null -> {
 49→                OpenStatsForSiteAndTimeframe(site, statsTimeframe)
 50→            }
 51→            site != null -> {
 52→                OpenStatsForSite(site)
 53→            }
 54→            statsTimeframe != null -> {
 55→                OpenStatsForTimeframe(statsTimeframe)
 56→            }
 57→            else -> {
 58→                // In other cases, launch stats with the current selected site.
 59→                OpenStats
 60→            }
 61→        }
 62→    }
 63→
 64→    /**
 65→     * Returns true if the URI should be handled by StatsLinkHandler.
 66→     * The handled links are `https://wordpress.com/stats/day/$site` and `wordpress://stats`
 67→     */
 68→    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 69→        return (uri.host == HOST_WORDPRESS_COM &&
 70→                uri.pathSegments.firstOrNull() == STATS_PATH) || uri.host == STATS_PATH
 71→    }
 72→
 73→    override fun stripUrl(uri: UriWrapper): String {
 74→        return buildString {
 75→            val offset = if (uri.host == STATS_PATH) {
 76→                append(APPLINK_SCHEME)
 77→                0
 78→            } else {
 79→                append("$HOST_WORDPRESS_COM/")
 80→                1
 81→            }
 82→            append(STATS_PATH)
 83→            val pathSegments = uri.pathSegments
 84→            val size = pathSegments.size
 85→            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 86→            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 87→            if (statsTimeframe != null) {
 88→                append("/$statsTimeframe")
 89→            }
 90→            if (hasSiteUrl) {
 91→                append("/$SITE_DOMAIN")
 92→            }
 93→        }
 94→    }
 95→
 96→    /**
 97→     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
 98→     * to the host.
 99→     */
100→    private fun String.toSite(): SiteModel? {
101→        return deepLinkUriUtils.hostToSite(this)
102→    }
103→
104→    private fun String.toStatsTimeframe(): StatsTimeframe? {
105→        return when (this) {
106→            "day" -> StatsTimeframe.DAY
107→            "week" -> StatsTimeframe.WEEK
108→            "month" -> StatsTimeframe.MONTH
109→            "year" -> StatsTimeframe.YEAR
110→            "insights" -> StatsTimeframe.INSIGHTS
111→            "traffic" -> StatsTimeframe.TRAFFIC
112→            "subscribers" -> StatsTimeframe.SUBSCRIBERS
113→            else -> null
114→        }
115→    }
116→
117→    companion object {
118→        private const val STATS_PATH = "stats"
119→    }
120→}
